52	   -- AXI bus, read master signal record
53	   --------------------------------------------------------
54	
55	   -- Base Record
56	   type AxiLiteReadMasterType is record
57	      -- Read Address channel
58	      araddr  : slv(31 downto 0);
59	      arprot  : slv(2 downto 0);
60	      arvalid : sl;
61	      -- Read data channel
62	      rready  : sl;
63	   end record;
64	
65	   -- Initialization constants
66	   constant AXI_LITE_READ_MASTER_INIT_C : AxiLiteReadMasterType := (
67	      araddr  => (others => '0'),
68	      arprot  => (others => '0'),
69	      arvalid => '0',
70	      rready  => '1'
71	      );
72	
73	   -- Array
74	   type AxiLiteReadMasterArray is array (natural range<>) of AxiLiteReadMasterType;
