631	   procedure axiSlaveRegister (
632	      signal axiWriteMaster  : in    AxiLiteWriteMasterType;
633	      signal axiReadMaster   : in    AxiLiteReadMasterType;
634	      variable axiWriteSlave : inout AxiLiteWriteSlaveType;
635	      variable axiReadSlave  : inout AxiLiteReadSlaveType;
636	      variable axiStatus     : in    AxiLiteStatusType;
637	      addr                   : in    slv;
638	      offset                 : in    integer;
639	      reg                    : inout slv;
640	      constAssign            : in    boolean := false;
641	      constVal               : in    slv     := "0") is
642	   begin
643	      -- Read must come first so as not to overwrite the variable if read and write happen at once
644	      if (axiStatus.readEnable = '1') then
645	         if (std_match(axiReadMaster.araddr(addr'length-1 downto 0), addr)) then
646	            axiReadSlave.rdata(offset+reg'length-1 downto offset) := reg;
647	            axiSlaveReadResponse(axiReadSlave);
648	         end if;
649	      end if;
650	
651	      if (axiStatus.writeEnable = '1') then
652	         if (std_match(axiWriteMaster.awaddr(addr'length-1 downto 0), addr)) then
653	            if (constAssign) then
654	               reg := constVal;
655	            else
656	               reg := axiWriteMaster.wdata(offset+reg'length-1 downto offset);
657	            end if;
658	            axiSlaveWriteResponse(axiWriteSlave);
659	         end if;
660	      end if;
661	
662	   end procedure;
