755	   procedure axiSlaveRegisterLegacy (
756	      variable ep : inout AxiLiteEndpointType;
757	      addr        : in    slv;
758	      offset      : in    integer;
759	      reg         : inout slv;
760	      constVal    : in    slv)
761	   is
762	      -- Need to remap addr range to be (length-1 downto 0)
763	      constant ADDR_LEN_C   : integer                    := addr'length;
764	      constant ADDR_C       : slv(ADDR_LEN_C-1 downto 0) := addr;
765	      -- Offset as measured from addr[1:0]="00"
766	      constant ABS_OFFSET_C : integer                    := offset + (to_integer(unsigned(ADDR_C(1 downto 0)))*8);
767	      -- Normalized address and offset (for when addr[1:0]!=00)
768	      constant NORMAL_ADDR_C : slv(ADDR_LEN_C-1 downto 0) := ite(ABS_OFFSET_C /= 0,
769	                                                                 slv((unsigned(slv(ADDR_C))) + ((ABS_OFFSET_C/32)*4)),
770	                                                                 ADDR_C);
771	      constant NORMAL_OFFSET_C : integer := ABS_OFFSET_C mod 32;
772	      -- Most significant register bit before wrapping to the next word address
773	      constant REG_HIGH_BIT_C  : integer := minimum(31-NORMAL_OFFSET_C+reg'low, reg'high);
774	      -- Most significant data bus bit to be used in this recursion (max out at 31)
775	      constant BUS_HIGH_BIT_C  : integer := minimum(NORMAL_OFFSET_C+reg'length-1, 31);
776	
777	      constant STROBE_MASK_C : slv(3 downto 0) := genAxiSlaveStrobeMask(BUS_HIGH_BIT_C, NORMAL_OFFSET_C);
778	   begin
779	
780	      -- Read must come first so as not to overwrite the variable if read and write happen at once
781	      if (ep.axiStatus.readEnable = '1') then
782	         if (std_match(ep.axiReadMaster.araddr(ADDR_LEN_C-1 downto 2), NORMAL_ADDR_C(ADDR_LEN_C-1 downto 2))) then
783	            ep.axiReadSlave.rdata(BUS_HIGH_BIT_C downto NORMAL_OFFSET_C) := reg(REG_HIGH_BIT_C downto reg'low);
784	            axiSlaveReadResponse(ep.axiReadSlave);
785	         end if;
786	      end if;
787	
788	      if (ep.axiStatus.writeEnable = '1') then
789	         if (std_match(ep.axiWriteMaster.awaddr(ADDR_LEN_C-1 downto 2), NORMAL_ADDR_C(ADDR_LEN_C-1 downto 2)) and
790	             std_match(ep.axiWriteMaster.wstrb, STROBE_MASK_C)) then
791	            if (constVal /= "X") then
792	               reg(REG_HIGH_BIT_C downto reg'low) := resize(constVal, (REG_HIGH_BIT_C-reg'low)+1);
793	            else
794	               reg(REG_HIGH_BIT_C downto reg'low) := ep.axiWriteMaster.wdata(BUS_HIGH_BIT_C downto NORMAL_OFFSET_C);
795	            end if;
796	            axiSlaveWriteResponse(ep.axiWriteSlave);
797	         end if;
798	      end if;
799	
800	   end procedure;
